void eeTypes_InitUnits() {
  PEETypes eTypes = game_GetEETypes();
  map<UnitClassType, map<UnitType, uint8_t> > *classTreeStructure = eTypes->classTreeStructure;

  for(auto &it : classDefUnits) {
    for(size_t i = 0, c = it.second.size(); i < c; i++) {
      (*classTreeStructure)[it.first][it.second[i]] = 1;
    }
  }
}

uint8_t eeTypes_IsFromClass(UnitClassType unitClass, UnitType unitType) {
  PEETypes eTypes = game_GetEETypes();
  map<UnitClassType, map<UnitType, uint8_t> > *classTreeStructure = eTypes->classTreeStructure;

  if(classTreeStructure->find(unitClass) == classTreeStructure->end()) {
    return 0;
  }
  return (*classTreeStructure)[unitClass].find(unitType) != (*classTreeStructure)[unitClass].end();
}

uint8_t eeTypes_IsWaterUnit(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_WATER_TRANSPORT, unitType) || 
         eeTypes_IsFromClass(CLASS_WATER_CARRIERS, unitType) ||
         eeTypes_IsFromClass(CLASS_WATER_FISHING_BOATS, unitType) ||
         eeTypes_IsFromClass(CLASS_WATER_BOATS, unitType) ||
         eeTypes_IsFromClass(CLASS_SUBMARINES, unitType);
}

uint8_t eeTypes_IsCitizen(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_CITIZENS, unitType);
}

uint8_t eeTypes_IsWaterTransport(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_WATER_TRANSPORT, unitType);
}